// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid input');
  }
  try {
    const member = await membersService.createMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return sendError(res, 409, error.code, error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let membersStore = [];

async function createMember(userId, role) {
  if (!userId || !role) {
    return null;
  }
  const existingMember = membersStore.find(m => m.userId === userId);
  if (existingMember) {
    throw { code: 'DUPLICATE', message: 'Member already exists' };
  }
  const member = { id: randomUUID(), userId, role };
  membersStore.push(member);
  return member;
}

module.exports = { createMember };

// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_DESCRIPTION', 'Invalid task description');
  }
  try {
    const task = await tasksService.createTask(description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTask(taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, error.code, error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let tasksStore = [];

async function createTask(description) {
  if (!description) {
    return null;
  }
  const task = { id: randomUUID(), description, status: 'todo' };
  tasksStore.push(task);
  return task;
}

async function getTasks(status) {
  if (status === 'done') {
    return tasksStore.filter(t => t.status === 'done');
  }
  return tasksStore;
}

async function updateTask(taskId, status) {
  const task = tasksStore.find(t => t.id === taskId);
  if (!task) {
    throw { code: 'NOT_FOUND', message: 'Task not found' };
  }
  task.status = status;
  return task;
}

module.exports = { createTask, getTasks, updateTask };

